package exercicios.oop.java.domain;import java.util.Scanner;public class Contador {    public int contador(int num){        Scanner inputContador = new Scanner(System.in);        System.out.println("Um número: ");        int numCont = inputContador.nextInt();        for (int cont = 1; cont <= numCont; cont++) {            System.out.println(cont);        }        return numCont;    }}